import React, { useEffect, useState } from "react";
import {
  Box,
  Divider,
  List,
  ListItemButton,
  ListItemText,
  Stack,
  Typography,
} from "@mui/material";
import { Link as RouterLink } from "react-router-dom";

import "./styles.css";
import fetchModel from "../../lib/fetchModelData";

/**
 * Define UserList, a React component of Project 4.
 */
function UserList() {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    const loadUsers = async () => {
      try {
        const userList = await fetchModel("/user/list");
        const usersWithCounts = await Promise.all(
          userList.map(async (user) => {
            try {
              const photos = await fetchModel(`/photosOfUser/${user._id}`);
              const commentCount = photos.reduce(
                (total, photo) => total + (photo.comments?.length || 0),
                0
              );

              return {
                ...user,
                photoCount: photos.length,
                commentCount,
              };
            } catch (error) {
              console.error(`Error fetching photos for user ${user._id}:`, error);
              return {
                ...user,
                photoCount: 0,
                commentCount: 0,
              };
            }
          })
        );

        setUsers(usersWithCounts);
      } catch (error) {
        console.error("Error fetching users:", error);
      }
    };

    loadUsers();
  }, []);

  return (
    <div className="user-list">
      <Typography variant="subtitle2" color="text.secondary" sx={{ px: 2, pt: 1, pb: 0.5 }}>
        Users
      </Typography>
      <List component="nav" dense disablePadding>
        {users.map((user) => (
          <React.Fragment key={user._id}>
            <ListItemButton
              component={RouterLink}
              to={`/users/${user._id}`}
            >
              <ListItemText
                primary={`${user.first_name} ${user.last_name}`}
                primaryTypographyProps={{ variant: "body2" }}
              />
              <Stack direction="row" spacing={1}>
                <Box className="user-list-bubble user-list-bubble-photo">
                  {user.photoCount ?? 0}
                </Box>
                <Box className="user-list-bubble user-list-bubble-comment">
                  {user.commentCount ?? 0}
                </Box>
              </Stack>
            </ListItemButton>
            <Divider component="li" />
          </React.Fragment>
        ))}
      </List>
    </div>
  );
}

export default UserList;
